/**
 * lib/llm-evidence.mjs — Gap-detection consumer for LLM usage evidence.
 *
 * Reads data/llm-usage-knowledge.json (generated by scripts/scan-llm-usage.mjs)
 * and provides gap-contradiction and compounding-signal lookups for dashboard
 * gap chips and role drawer popouts.
 *
 * Pure deterministic — NO LLM calls, regex/keyword only.
 * In-memory cache of the JSON after first load.
 */

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const KNOWLEDGE_PATH = resolve(__dirname, '..', 'data', 'llm-usage-knowledge.json');

let _cache = null;

// ── Gap keyword → provider mapping ───────────────────────────────────────────
// Each entry: { gapPattern: RegExp, providers: [string], confidence: 'high'|'medium' }

const GAP_PROVIDER_MAP = [
  {
    gapPatterns: [/claude[\s_-]?code/i, /claude[\s_-]?specific/i, /anthropic[\s_-]?cli/i, /mcp[\s_-]?integration/i],
    providers: ['claude_code'],
    confidence: 'high',
    template: 'The career-ops repository itself is built as a Claude Code-native system: {evidence}. This repo has {count} evidence items across sub-agent fan-outs, worktree isolation, MCP tool integrations, and agent-attributed commits.',
  },
  {
    gapPatterns: [/llm[\s_-]?api/i, /ai[\s_-]?api/i, /anthropic[\s_-]?api/i, /openai[\s_-]?api/i, /language[\s_-]?model[\s_-]?api/i],
    providers: ['anthropic_api', 'gemini', 'ollama'],
    confidence: 'high',
    template: 'Production LLM API usage is documented across multiple providers: {evidence}. Advanced patterns include prompt caching, multi-provider routing, circuit breakers, and batch processing.',
  },
  {
    gapPatterns: [/multi[\s_-]?model/i, /multi[\s_-]?llm/i, /provider[\s_-]?routing/i, /model[\s_-]?routing/i],
    providers: ['claude_code', 'anthropic_api', 'gemini', 'ollama'],
    confidence: 'high',
    template: 'Mitchell\'s career-ops system implements explicit multi-provider routing (Ollama → Anthropic Haiku → Gemini Flash) with circuit breakers and fallback chains: {evidence}.',
  },
  {
    gapPatterns: [/agentic/i, /autonomous[\s_-]?agent/i, /agent[\s_-]?orchestrat/i, /multi[\s_-]?agent/i],
    providers: ['claude_code'],
    confidence: 'high',
    template: 'The career-ops system is a production multi-agent orchestration platform with documented sub-agent fan-outs, worktree isolation, and autonomous build sessions: {evidence}.',
  },
  {
    gapPatterns: [/prompt[\s_-]?engineer/i, /prompt[\s_-]?design/i, /prompt[\s_-]?optim/i],
    providers: ['anthropic_api', 'gemini'],
    confidence: 'high',
    template: 'Advanced prompt engineering patterns are evidenced across multiple LLM integrations: {evidence}. Includes few-shot examples, Zod-validated JSON schemas, temperature tuning, and cache_control optimization.',
  },
  {
    gapPatterns: [/cost[\s_-]?optim/i, /token[\s_-]?optim/i, /llm[\s_-]?cost/i],
    providers: ['anthropic_api'],
    confidence: 'high',
    template: 'Cost optimization at the LLM API layer is documented: {evidence}. Includes prompt caching, max_token tuning, budget guards, monthly spend tracking, and local inference fallback.',
  },
  {
    gapPatterns: [/python/i, /javascript/i, /typescript/i, /node[\s_-]?js/i],
    providers: ['claude_code', 'anthropic_api'],
    confidence: 'medium',
    template: 'The career-ops system is a 60+ script Node.js/ESM codebase with production LLM integrations: {evidence}.',
  },
  {
    gapPatterns: [/developer[\s_-]?tool/i, /ai[\s_-]?tooling/i, /ai[\s_-]?platform/i, /ai[\s_-]?infrastructure/i],
    providers: ['claude_code'],
    confidence: 'high',
    template: 'Mitchell has built production AI tooling and developer platforms: {evidence}. The career-ops system serves as a live demonstration of applied AI infrastructure.',
  },
  {
    gapPatterns: [/batch[\s_-]?process/i, /pipeline[\s_-]?autom/i, /data[\s_-]?pipeline/i],
    providers: ['anthropic_api'],
    confidence: 'high',
    template: 'Production batch processing pipelines over LLM APIs are documented: {evidence}. Includes rate limiting, retry logic, cost tracking, and checkpoint recovery.',
  },
];

// ── Load + validate ───────────────────────────────────────────────────────────

/**
 * loadKnowledgeBase() → knowledge object or null
 * Validates schema_version. Caches in-memory.
 */
export function loadKnowledgeBase() {
  if (_cache) return _cache;
  if (!existsSync(KNOWLEDGE_PATH)) return null;
  try {
    const raw = readFileSync(KNOWLEDGE_PATH, 'utf8');
    const parsed = JSON.parse(raw);
    if (!parsed.schema_version || !parsed.providers) {
      throw new Error('Invalid schema: missing schema_version or providers');
    }
    _cache = parsed;
    return _cache;
  } catch {
    return null;
  }
}

/** Invalidate the in-memory cache (useful in tests). */
export function clearCache() {
  _cache = null;
}

// ── Gap checking ──────────────────────────────────────────────────────────────

/**
 * checkGap(gapKey, role?) → { contradicts, evidence_summary, draft_response, citations }
 *
 * @param {string} gapKey  — text of the gap claim, e.g. "Claude Code specific usage"
 * @param {object} [role]  — optional role context (unused in v1 but wired for future use)
 */
export function checkGap(gapKey, role = {}) {
  const kb = loadKnowledgeBase();
  if (!kb) {
    return {
      contradicts: false,
      evidence_summary: 'Knowledge base not yet generated. Run: node scripts/scan-llm-usage.mjs',
      draft_response: '',
      citations: [],
    };
  }

  // Find matching gap rule
  let matchedRule = null;
  for (const rule of GAP_PROVIDER_MAP) {
    if (rule.gapPatterns.some(re => re.test(gapKey))) {
      matchedRule = rule;
      break;
    }
  }

  if (!matchedRule) {
    return {
      contradicts: false,
      evidence_summary: `No LLM evidence rule matched for gap: "${gapKey}"`,
      draft_response: '',
      citations: [],
    };
  }

  // Gather evidence from matched providers
  const allEvidence = [];
  const citations = [];
  let evidenceCount = 0;
  let highestCount = 0;

  for (const provKey of matchedRule.providers) {
    const prov = kb.providers[provKey];
    if (!prov || prov.evidence_count === 0) continue;
    evidenceCount += prov.evidence_count;
    if (prov.evidence_count > highestCount) highestCount = prov.evidence_count;

    for (const uc of (prov.use_cases || []).slice(0, 3)) {
      allEvidence.push(uc.name);
      citations.push({ file: uc.ref, lineStart: null, lineEnd: null, excerpt: uc.evidence });
    }
    for (const cs of (prov.compounding_signals || []).slice(0, 2)) {
      allEvidence.push(cs.pattern);
    }
  }

  const contradicts = evidenceCount > 0;
  if (!contradicts) {
    return {
      contradicts: false,
      evidence_summary: `No evidence found for providers: ${matchedRule.providers.join(', ')}`,
      draft_response: '',
      citations: [],
    };
  }

  const evidenceSummary = allEvidence.slice(0, 5).join('; ');
  const draftResponse = matchedRule.template
    .replace('{evidence}', evidenceSummary)
    .replace('{count}', String(evidenceCount));

  return {
    contradicts: true,
    evidence_summary: evidenceSummary,
    draft_response: draftResponse,
    citations,
    confidence: matchedRule.confidence,
    evidence_count: evidenceCount,
  };
}

// ── Evidence card renderer ─────────────────────────────────────────────────────

/**
 * renderEvidenceCard(result) → HTML string
 * For inline display when a gap chip is contradicted.
 */
export function renderEvidenceCard(result) {
  if (!result || !result.contradicts) return '';

  const citationLinks = (result.citations || [])
    .slice(0, 3)
    .map(c => `<span class="evidence-ref" title="${escHtml(c.excerpt || '')}">${escHtml(c.file || '')}</span>`)
    .join('');

  return `<div class="evidence-card evidence-card--contradicts" role="note" aria-label="Gap contradicted by local evidence">
  <div class="evidence-card__header">
    <span class="evidence-card__icon" aria-hidden="true">✓</span>
    <span class="evidence-card__label">Evidence contradicts this gap</span>
    <span class="evidence-card__confidence">confidence: ${escHtml(result.confidence || 'medium')}</span>
  </div>
  <p class="evidence-card__summary">${escHtml(result.evidence_summary)}</p>
  <p class="evidence-card__draft">${escHtml(result.draft_response)}</p>
  ${citationLinks ? `<div class="evidence-card__refs">${citationLinks}</div>` : ''}
</div>`;
}

function escHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

// ── Compounding signals for a role ────────────────────────────────────────────

/**
 * surfaceCompoundingFor(role) → [{ pattern, observed_at, evidence_ref }]
 * Shows how Mitchell's LLM skills are compounding for a specific role.
 */
export function surfaceCompoundingFor(role = {}) {
  const kb = loadKnowledgeBase();
  if (!kb) return [];

  const signals = [];

  // Pull compounding signals from all providers
  for (const [provKey, prov] of Object.entries(kb.providers)) {
    for (const cs of (prov.compounding_signals || [])) {
      signals.push({
        pattern: cs.pattern,
        observed_at: cs.date,
        evidence_ref: provKey,
        provider: provKey,
      });
    }
  }

  // If role has keywords, filter to relevant signals
  const roleName = (role.title || role.role || '').toLowerCase();
  const roleCompany = (role.company || '').toLowerCase();

  if (roleName || roleCompany) {
    const aiRolePattern = /ai|llm|agent|automation|ml|machine\s+learning|nlp|language\s+model/i;
    if (aiRolePattern.test(roleName)) {
      // For AI roles, return all signals — they're all relevant
      return signals.sort((a, b) => (b.observed_at || '').localeCompare(a.observed_at || ''));
    }
    // For non-AI roles, return only the most transferable signals
    return signals
      .filter(s => /cost|automat|pipeline|batch|production|api/i.test(s.pattern))
      .sort((a, b) => (b.observed_at || '').localeCompare(a.observed_at || ''));
  }

  return signals.sort((a, b) => (b.observed_at || '').localeCompare(a.observed_at || ''));
}

// ── Summary accessor ──────────────────────────────────────────────────────────

/**
 * getProviderSummary() → { provider: { evidence_count, latest_use_date, top_use_cases } }
 * Lightweight summary for dashboard widgets.
 */
export function getProviderSummary() {
  const kb = loadKnowledgeBase();
  if (!kb) return {};
  const summary = {};
  for (const [k, v] of Object.entries(kb.providers)) {
    summary[k] = {
      evidence_count: v.evidence_count,
      latest_use_date: v.latest_use_date,
      top_use_cases: (v.use_cases || []).slice(0, 3).map(u => u.name),
    };
  }
  return summary;
}
